blocks.body:
{
    "level": "A2",
    "intro": "W tym temacie dowiesz się <strong>co to jest głos bierny</strong>, czym różni się od głosu czynnego i w jakich przypadkach jest używany.",
    "rules": [
        {
            "label": "Aktywny",
            "color": "emerald",
            "text": "<strong>Stan aktywny</strong> — podmiot wykonuje akcję:",
            "example": "Tom writes a letter."
        },
        {
            "label": "Pasywny",
            "color": "blue",
            "text": "<strong>Stan pasywny</strong> — podmiot otrzymuje akcję:",
            "example": "A letter is written by Tom."
        },
        {
            "label": "Gdy?",
            "color": "rose",
            "text": "Gdy wykonawca jest <strong>nieznany, nieważny</strong> lub oczywisty:",
            "example": "The window was broken."
        }
    ]
}

{
    "title": "1. Co to jest aktywny i pasywny?",
    "intro": "W języku angielskim zdanie może mieć dwa stany:",
    "items": [
        {
            "label": "Aktywny głos",
            "title": "Aktywny",
            "subtitle": "Podmiot wykonuje czynność. Skoncentruj się na wykonawcy."
        },
        {
            "label": "Strona bierna",
            "title": "Pasywny",
            "subtitle": "Podmiot zyskuje akcję. Skoncentruj się na działaniu lub wyniku."
        },
        {
            "label": "Transformacja",
            "title": "Obiekt → Temat",
            "subtitle": "Dopełnienie zdania czynnego staje się podmiotem w stronie biernej."
        },
        {
            "label": "Agent",
            "title": "Wykonawca (przez)",
            "subtitle": "Artystę można określić za pomocą „by”, ale często jest to pomijane."
        }
    ]
}

{
    "title": "2. Porównanie trybu aktywnego i pasywnego",
    "sections": [
        {
            "label": "Aktywny głos",
            "color": "emerald",
            "description": "Podmiot <strong>wykonuje</strong> akcję. Struktura: <strong>Podmiot + Czasownik + Dopełnienie</strong>",
            "examples": [
                {
                    "en": "Tom writes a letter.",
                    "ua": "Tomek pisze list. (Tom jest wykonawcą)"
                },
                {
                    "en": "She cleaned the room.",
                    "ua": "Posprzątała pokój."
                },
                {
                    "en": "They build houses.",
                    "ua": "Budują domy."
                }
            ]
        },
        {
            "label": "Strona bierna",
            "color": "blue",
            "description": "Podmiot <strong>dostaje</strong> akcję. Struktura: <strong>Temat + być + V3 (+ przez agenta)</strong>",
            "examples": [
                {
                    "en": "A letter is written by Tom.",
                    "ua": "List został napisany przez Tomka. (Skoncentruj się na literze)"
                },
                {
                    "en": "The room was cleaned.",
                    "ua": "Pokój został posprzątany."
                },
                {
                    "en": "Houses are built here.",
                    "ua": "Tu buduje się domy."
                }
            ]
        }
    ]
}

{
    "title": "3. Kiedy stosować głos bierny?",
    "sections": [
        {
            "label": "1. Wykonawca jest nieznany",
            "color": "emerald",
            "description": "Nie wiemy, kto wykonał tę czynność:",
            "examples": [
                {
                    "en": "My car was stolen.",
                    "ua": "Mój samochód został skradziony. (Nie wiemy kto)"
                },
                {
                    "en": "The window was broken.",
                    "ua": "Okno było rozbite."
                }
            ]
        },
        {
            "label": "2. Wykonawca jest nieważny",
            "color": "sky",
            "description": "Nie interesuje nas, kto wykonuje akcję. Ważny wynik:",
            "examples": [
                {
                    "en": "English is spoken here.",
                    "ua": "Mówi się tu po angielsku."
                },
                {
                    "en": "The building was constructed in 1990.",
                    "ua": "Budynek został wybudowany w 1990 roku."
                }
            ]
        },
        {
            "label": "3. Wykonawca jest oczywisty",
            "color": "amber",
            "description": "Jasne jest, kto wykonuje akcję, więc nie podajemy jego imienia:",
            "examples": [
                {
                    "en": "He was arrested.",
                    "ua": "Został aresztowany. (policja - oczywiście)"
                },
                {
                    "en": "The letter was delivered.",
                    "ua": "Dostarczono listy. (poczta jest oczywista)"
                }
            ]
        },
        {
            "label": "4. Styl formalno-naukowy",
            "color": "rose",
            "description": "W tekstach naukowych i dokumentach urzędowych strona bierna brzmi bardziej obiektywnie:",
            "examples": [
                {
                    "en": "The experiment was conducted.",
                    "ua": "Eksperyment został przeprowadzony."
                },
                {
                    "en": "It is believed that...",
                    "ua": "Uważa się, że..."
                }
            ]
        }
    ]
}

{
    "title": "4. Transformacja aktywna → pasywna",
    "intro": "Jak zmienić zdanie z czynnego na bierne:",
    "rows": [
        {
            "en": "Active: Tom writes a letter.",
            "ua": "(Temat: Tomek, Przedmiot: list)",
            "note": "→ Passive: A letter is written by Tom."
        },
        {
            "en": "Active: She cleaned the room.",
            "ua": "(Temat: Ona, Przedmiot: pokój)",
            "note": "→ Passive: The room was cleaned (by her)."
        },
        {
            "en": "Active: They build houses.",
            "ua": "(Temat: Oni, Przedmiot: domy)",
            "note": "→ Passive: Houses are built."
        }
    ],
    "warning": "📌 <strong>Przedmiot</strong> zdania czynnego staje się <strong>Podmiotem</strong> zdania biernego!"
}

{
    "title": "5. Krótkie podsumowanie",
    "items": [
        "<strong>Aktywny głos</strong>: podmiot wykonuje akcję → Tomek pisze list.",
        "<strong>Głos bierny</strong>: podmiot otrzymuje akcję → Napisano list.",
        "<strong>Obiekt → Temat</strong>: dopełnienie zdania czynnego staje się podmiotem strony biernej.",
        "<strong>Kiedy używać</strong>: artysta nieznany, nieważny, oczywisty lub w stylu formalnym.",
        "<strong>Agent (autor)</strong>: wskazuje artystę, ale często jest pomijany."
    ]
}

{
    "title": "Pozostałe strony z podstawami strony biernej",
    "items": [
        {
            "label": "Co to jest głos pasywny? (aktualny)",
            "current": true
        },
        {
            "label": "Forma: be + V3 (imiesłów bierny)",
            "current": false
        },
        {
            "label": "Czas teraźniejszy prosty pasywny",
            "current": false
        },
        {
            "label": "Czas przeszły prosty bierny",
            "current": false
        }
    ]
}
